retryLogic.pattern:
// composables/useRetry.ts
export function useRetry(fn, maxAttempts = 3) {
  let attempts = 0;

  async function retry() {
    try {
      return await fn();
    } catch (error) {
      if (++attempts < maxAttempts) {
        await new Promise(r => setTimeout(r, 1000 * attempts));
        return retry();
      }
      throw error;
    }
  }

  return retry;
}
